   359→// intersectConstraints intersects two constraints (for AND operations)
   360→func (a *JobTriggerAnalyzer) intersectConstraints(left, right *eventNameConstraint) *eventNameConstraint {
   361→	result := &eventNameConstraint{
   362→		included: make(map[string]bool),
   363→		excluded: make(map[string]bool),
   364→	}
