   366→	// For AND, included must be in both (if both have included lists)
   367→	// If one has included and one has excluded, apply both
   368→	if len(left.included) > 0 && len(right.included) > 0 {
   369→		// Intersection of included sets
   370→		for k := range left.included {
   371→			if right.included[k] {
   372→				result.included[k] = true
   373→			}
   374→		}
   375→	} else if len(left.included) > 0 {
   376→		for k := range left.included {
   377→			result.included[k] = true
   378→		}
   379→	} else if len(right.included) > 0 {
   380→		for k := range right.included {
   381→			result.included[k] = true
   382→		}
   383→	}
   384→
   385→	// Union of excluded sets for AND
   386→	for k := range left.excluded {
   387→		result.excluded[k] = true
   388→	}
   389→	for k := range right.excluded {
   390→		result.excluded[k] = true
   391→	}
   392→
   393→	return result
   394→}
   395→
   396→// unionConstraints unions two constraints (for OR operations)
   397→func (a *JobTriggerAnalyzer) unionConstraints(left, right *eventNameConstraint) *eventNameConstraint {
   398→	result := &eventNameConstraint{
   399→		included: make(map[string]bool),
   400→		excluded: make(map[string]bool),
   401→	}
   402→
   403→	// For OR, union of included sets
   404→	for k := range left.included {
   405→		result.included[k] = true
   406→	}
   407→	for k := range right.included {
   408→		result.included[k] = true
   409→	}
   410→
   411→	// For OR, intersection of excluded sets (both must exclude)
   412→	if len(left.excluded) > 0 && len(right.excluded) > 0 {
   413→		for k := range left.excluded {
   414→			if right.excluded[k] {
   415→				result.excluded[k] = true
   416→			}
   417→		}
   418→	}
   419→
   420→	return result
   421→}
   422→
   423→// applyConstraints applies the constraints to the workflow triggers
   424→func (a *JobTriggerAnalyzer) applyConstraints(constraints *eventNameConstraint) []string {
   425→	var result []string
   426→
   427→	for _, trigger := range a.workflowTriggers {
   428→		// If there's an included list, the trigger must be in it
   429→		if len(constraints.included) > 0 {
   430→			if !constraints.included[trigger] {
   431→				continue
   432→			}
   433→		}
   434→
   435→		// If the trigger is excluded, skip it
   436→		if constraints.excluded[trigger] {
   437→			continue
   438→		}
   439→
   440→		result = append(result, trigger)
   441→	}
   442→
   443→	return result
   444→}
