    20→	// workflowTriggers stores all trigger names from the workflow
    21→	workflowTriggers []string
    22→	// jobHasMatchingTriggers indicates if the current job can execute on matching triggers
    23→	// (privileged for critical, normal for medium)
    24→	jobHasMatchingTriggers bool
    25→}
