    33→// untrustedExprInfo contains information about an untrusted expression
    34→type untrustedExprInfo struct {
    35→	expr          parsedExpression
    36→	paths         []string
    37→	isInRunScript bool       // true for run:, false for script: in github-script
    38→	scriptInput   *ast.Input // only set if isInRunScript is false
    39→}
