    48→// newCodeInjectionRule creates a new code injection rule with the specified severity level
    49→func newCodeInjectionRule(severityLevel string, checkPrivileged bool) *CodeInjectionRule {
    50→	var desc string
    51→
    52→	if checkPrivileged {
    53→		desc = "Checks for code injection vulnerabilities when untrusted input is used directly in run scripts or script actions with privileged workflow triggers (pull_request_target, workflow_run, issue_comment). See https://sisaku-security.github.io/lint/docs/rules/codeinjectioncritical/"
    54→	} else {
    55→		desc = "Checks for code injection vulnerabilities when untrusted input is used directly in run scripts or script actions with normal workflow triggers (pull_request, push, etc.). See https://sisaku-security.github.io/lint/docs/rules/codeinjectionmedium/"
    56→	}
    57→
    58→	return &CodeInjectionRule{
    59→		BaseRule: BaseRule{
    60→			RuleName: "code-injection-" + severityLevel,
    61→			RuleDesc: desc,
    62→		},
    63→		severityLevel:      severityLevel,
    64→		checkPrivileged:    checkPrivileged,
    65→		stepsWithUntrusted: make([]*stepWithUntrustedInput, 0),
    66→	}
    67→}
