    69→// VisitWorkflowPre is called before visiting a workflow
    70→func (rule *CodeInjectionRule) VisitWorkflowPre(node *ast.Workflow) error {
    71→	rule.workflow = node
    72→	rule.workflowTriggers = nil
    73→	rule.jobHasMatchingTriggers = false
    74→
    75→	// Collect all workflow triggers
    76→	for _, event := range node.On {
    77→		switch e := event.(type) {
    78→		case *ast.WebhookEvent:
    79→			if e.Hook != nil {
    80→				rule.workflowTriggers = append(rule.workflowTriggers, e.Hook.Value)
    81→			}
    82→		case *ast.WorkflowCallEvent:
    83→			rule.workflowTriggers = append(rule.workflowTriggers, "workflow_call")
    84→		}
    85→	}
    86→
    87→	return nil
    88→}
    89→
    90→func (rule *CodeInjectionRule) VisitJobPre(node *ast.Job) error {
    91→	// Reset job-level state
    92→	rule.jobHasMatchingTriggers = false
    93→
    94→	// Use JobTriggerAnalyzer to determine effective triggers for this job
    95→	// This considers job-level if conditions that may filter out certain triggers
    96→	analyzer := NewJobTriggerAnalyzer(rule.workflowTriggers)
    97→	effectiveTriggers := analyzer.AnalyzeJobTriggers(node)
    98→
    99→	// Check if this job can run on privileged triggers
   100→	hasPrivileged := false
   101→	hasNormal := false
   102→	for _, trigger := range effectiveTriggers {
   103→		if isPrivilegedTrigger(trigger) {
   104→			hasPrivileged = true
   105→		} else {
   106→			hasNormal = true
   107→		}
   108→	}
   109→
   110→	// Determine if this job matches what we're looking for
   111→	if rule.checkPrivileged {
   112→		// Critical rule: only check jobs that can run on privileged triggers
   113→		rule.jobHasMatchingTriggers = hasPrivileged
   114→	} else {
   115→		// Medium rule: only check jobs that can run on normal triggers
   116→		// but NOT on privileged triggers (to avoid duplicate warnings)
   117→		rule.jobHasMatchingTriggers = hasNormal && !hasPrivileged
   118→	}
   119→
   120→	// Skip if this job doesn't match our trigger criteria
   121→	if !rule.jobHasMatchingTriggers {
   122→		return nil
   123→	}
   124→
   125→	// Initialize taint tracker per job to avoid cross-job contamination
   126→	// This ensures step IDs don't collide across different jobs
   127→	rule.taintTracker = NewTaintTracker()
   128→
   129→	// First pass: collect taint information from all steps
   130→	// This allows us to detect tainted step outputs before checking for code injection
   131→	for _, s := range node.Steps {
   132→		rule.taintTracker.AnalyzeStep(s)
   133→	}
   134→
   135→	// Second pass: check for code injection vulnerabilities
   136→	for _, s := range node.Steps {
   137→		if s.Exec == nil {
   138→			continue
   139→		}
   140→
   141→		var stepUntrusted *stepWithUntrustedInput
   142→
   143→		// Check run: scripts
   144→		if s.Exec.Kind() == ast.ExecKindRun {
   145→			run := s.Exec.(*ast.ExecRun)
   146→			exprs := rule.extractAndParseExpressions(run.Run)
   147→
   148→			for _, expr := range exprs {
   149→				// Use checkUntrustedInputWithTaint to also detect tainted step outputs
   150→				untrustedPaths := rule.checkUntrustedInputWithTaint(expr)
   151→				if len(untrustedPaths) > 0 && !rule.isDefinedInEnv(expr, s.Env) {
   152→					if stepUntrusted == nil {
   153→						stepUntrusted = &stepWithUntrustedInput{step: s}
   154→					}
   155→					stepUntrusted.untrustedExprs = append(stepUntrusted.untrustedExprs, untrustedExprInfo{
   156→						expr:          expr,
   157→						paths:         untrustedPaths,
   158→						isInRunScript: true,
   159→					})
   160→
   161→					if rule.checkPrivileged {
   162→						rule.Errorf(
   163→							expr.pos,
   164→							"code injection (critical): \"%s\" is potentially untrusted and used in a workflow with privileged triggers. Avoid using it directly in inline scripts. Instead, pass it through an environment variable. See https://sisaku-security.github.io/lint/docs/rules/codeinjectioncritical/",
   165→							strings.Join(untrustedPaths, "\", \""),
   166→						)
   167→					} else {
   168→						rule.Errorf(
   169→							expr.pos,
   170→							"code injection (medium): \"%s\" is potentially untrusted. Avoid using it directly in inline scripts. Instead, pass it through an environment variable. See https://sisaku-security.github.io/lint/docs/rules/codeinjectionmedium/",
   171→							strings.Join(untrustedPaths, "\", \""),
   172→						)
   173→					}
   174→				}
   175→			}
   176→		}
   177→
   178→		// Check actions/github-script script: parameter
   179→		if s.Exec.Kind() == ast.ExecKindAction {
   180→			action := s.Exec.(*ast.ExecAction)
   181→			if action.Uses != nil && strings.HasPrefix(action.Uses.Value, "actions/github-script@") {
   182→				if scriptInput, ok := action.Inputs["script"]; ok && scriptInput != nil && scriptInput.Value != nil {
   183→					exprs := rule.extractAndParseExpressions(scriptInput.Value)
   184→
   185→					for _, expr := range exprs {
   186→						// Use checkUntrustedInputWithTaint to also detect tainted step outputs
   187→						untrustedPaths := rule.checkUntrustedInputWithTaint(expr)
   188→						if len(untrustedPaths) > 0 && !rule.isDefinedInEnv(expr, s.Env) {
   189→							if stepUntrusted == nil {
   190→								stepUntrusted = &stepWithUntrustedInput{step: s}
   191→							}
   192→							stepUntrusted.untrustedExprs = append(stepUntrusted.untrustedExprs, untrustedExprInfo{
   193→								expr:          expr,
   194→								paths:         untrustedPaths,
   195→								isInRunScript: false,
   196→								scriptInput:   scriptInput,
   197→							})
   198→
   199→							if rule.checkPrivileged {
   200→								rule.Errorf(
   201→									expr.pos,
   202→									"code injection (critical): \"%s\" is potentially untrusted and used in a workflow with privileged triggers. Avoid using it directly in github-script. Instead, pass it through an environment variable. See https://sisaku-security.github.io/lint/docs/rules/codeinjectioncritical/",
   203→									strings.Join(untrustedPaths, "\", \""),
   204→								)
   205→							} else {
   206→								rule.Errorf(
   207→									expr.pos,
   208→									"code injection (medium): \"%s\" is potentially untrusted. Avoid using it directly in github-script. Instead, pass it through an environment variable. See https://sisaku-security.github.io/lint/docs/rules/codeinjectionmedium/",
   209→									strings.Join(untrustedPaths, "\", \""),
   210→								)
   211→							}
   212→						}
   213→					}
   214→				}
   215→			}
   216→		}
   217→
   218→		if stepUntrusted != nil {
   219→			rule.stepsWithUntrusted = append(rule.stepsWithUntrusted, stepUntrusted)
   220→			rule.AddAutoFixer(NewStepFixer(s, rule))
   221→		}
   222→
   223→		envVarsWithUntrusted := rule.extractEnvVarsWithUntrustedInput(s)
   224→		if len(envVarsWithUntrusted) > 0 {
   225→			rule.checkShellMetacharacterInjection(s, envVarsWithUntrusted)
   226→		}
   227→		rule.checkDangerousShellPatterns(s)
   228→	}
   229→	return nil
   230→}
