   232→// RuleNames implements StepFixer interface
   233→func (rule *CodeInjectionRule) RuleNames() string {
   234→	return rule.RuleName
   235→}
   236→
   237→// FixStep implements StepFixer interface
   238→func (rule *CodeInjectionRule) FixStep(step *ast.Step) error {
   239→	// Find the stepWithUntrustedInput for this step
   240→	var stepInfo *stepWithUntrustedInput
   241→	for _, s := range rule.stepsWithUntrusted {
   242→		if s.step == step {
   243→			stepInfo = s
   244→			break
   245→		}
   246→	}
   247→
   248→	if stepInfo == nil {
   249→		return nil
   250→	}
   251→
   252→	// Ensure env exists in AST
   253→	if step.Env == nil {
   254→		step.Env = &ast.Env{
   255→			Vars: make(map[string]*ast.EnvVar),
   256→		}
   257→	}
   258→	if step.Env.Vars == nil {
   259→		step.Env.Vars = make(map[string]*ast.EnvVar)
   260→	}
   261→
   262→	// Group expressions by their raw content to avoid duplicates
   263→	envVarMap := make(map[string]string)      // expr.raw -> env var name
   264→	envVarsForYAML := make(map[string]string) // env var name -> env var value (for BaseNode)
   265→
   266→	for _, untrustedInfo := range stepInfo.untrustedExprs {
   267→		expr := untrustedInfo.expr
   268→
   269→		// Generate environment variable name from the untrusted path
   270→		envVarName := rule.generateEnvVarName(untrustedInfo.paths[0])
   271→
   272→		// Check if we already created an env var for this expression
   273→		if _, exists := envVarMap[expr.raw]; !exists {
   274→			envVarMap[expr.raw] = envVarName
   275→
   276→			// Add to env if not already present
   277→			if _, exists := step.Env.Vars[strings.ToLower(envVarName)]; !exists {
   278→				step.Env.Vars[strings.ToLower(envVarName)] = &ast.EnvVar{
   279→					Name: &ast.String{
   280→						Value: envVarName,
   281→						Pos:   expr.pos,
   282→					},
   283→					Value: &ast.String{
   284→						Value: fmt.Sprintf("${{ %s }}", expr.raw),
   285→						Pos:   expr.pos,
   286→					},
   287→				}
   288→				// Also track for BaseNode update
   289→				envVarsForYAML[envVarName] = fmt.Sprintf("${{ %s }}", expr.raw)
   290→			}
   291→		}
   292→	}
   293→
   294→	// Update BaseNode with env vars
   295→	if step.BaseNode != nil && len(envVarsForYAML) > 0 {
   296→		if err := AddEnvVarsToStepNode(step.BaseNode, envVarsForYAML); err != nil {
   297→			return fmt.Errorf("failed to add env vars to step node: %w", err)
   298→		}
   299→	}
   300→
   301→	// Build replacement maps for run: and script:
   302→	runReplacements := make(map[string]string)
   303→	scriptReplacements := make(map[string]string)
   304→
   305→	for _, untrustedInfo := range stepInfo.untrustedExprs {
   306→		envVarName := envVarMap[untrustedInfo.expr.raw]
   307→
   308→		if untrustedInfo.isInRunScript {
   309→			// For run: scripts, use $ENV_VAR
   310→			runReplacements[fmt.Sprintf("${{ %s }}", untrustedInfo.expr.raw)] = fmt.Sprintf("$%s", envVarName)
   311→			runReplacements[fmt.Sprintf("${{%s}}", untrustedInfo.expr.raw)] = fmt.Sprintf("$%s", envVarName)
   312→
   313→			// Also update AST
   314→			run := step.Exec.(*ast.ExecRun)
   315→			if run.Run != nil {
   316→				run.Run.Value = strings.ReplaceAll(
   317→					run.Run.Value,
   318→					fmt.Sprintf("${{ %s }}", untrustedInfo.expr.raw),
   319→					fmt.Sprintf("$%s", envVarName),
   320→				)
   321→				run.Run.Value = strings.ReplaceAll(
   322→					run.Run.Value,
   323→					fmt.Sprintf("${{%s}}", untrustedInfo.expr.raw),
   324→					fmt.Sprintf("$%s", envVarName),
   325→				)
   326→			}
   327→		} else {
   328→			// For github-script, use process.env.ENV_VAR
   329→			scriptReplacements[fmt.Sprintf("${{ %s }}", untrustedInfo.expr.raw)] = fmt.Sprintf("process.env.%s", envVarName)
   330→			scriptReplacements[fmt.Sprintf("${{%s}}", untrustedInfo.expr.raw)] = fmt.Sprintf("process.env.%s", envVarName)
   331→
   332→			// Also update AST
   333→			if untrustedInfo.scriptInput != nil && untrustedInfo.scriptInput.Value != nil {
   334→				untrustedInfo.scriptInput.Value.Value = strings.ReplaceAll(
   335→					untrustedInfo.scriptInput.Value.Value,
   336→					fmt.Sprintf("${{ %s }}", untrustedInfo.expr.raw),
   337→					fmt.Sprintf("process.env.%s", envVarName),
   338→				)
   339→				untrustedInfo.scriptInput.Value.Value = strings.ReplaceAll(
   340→					untrustedInfo.scriptInput.Value.Value,
   341→					fmt.Sprintf("${{%s}}", untrustedInfo.expr.raw),
   342→					fmt.Sprintf("process.env.%s", envVarName),
   343→				)
   344→			}
   345→		}
   346→	}
   347→
   348→	// Update BaseNode with replacements
   349→	if step.BaseNode != nil {
   350→		if len(runReplacements) > 0 {
   351→			if err := ReplaceInRunScript(step.BaseNode, runReplacements); err != nil {
   352→				// Ignore error if run section doesn't exist (might be github-script)
   353→				if !strings.Contains(err.Error(), "run section not found") {
   354→					return fmt.Errorf("failed to replace in run script: %w", err)
   355→				}
   356→			}
   357→		}
   358→		if len(scriptReplacements) > 0 {
   359→			if err := ReplaceInGitHubScript(step.BaseNode, scriptReplacements); err != nil {
   360→				// Ignore error if with/script section doesn't exist (might be run:)
   361→				if !strings.Contains(err.Error(), "section not found") && !strings.Contains(err.Error(), "field not found") {
   362→					return fmt.Errorf("failed to replace in github-script: %w", err)
   363→				}
   364→			}
   365→		}
   366→	}
   367→
   368→	return nil
   369→}
