   371→// generateEnvVarName generates an environment variable name from an untrusted path
   372→func (rule *CodeInjectionRule) generateEnvVarName(path string) string {
   373→	parts := strings.Split(path, ".")
   374→	if len(parts) == 0 {
   375→		return "UNTRUSTED_INPUT"
   376→	}
   377→
   378→	// Common patterns
   379→	if len(parts) >= 4 && parts[0] == ContextGithub && parts[1] == EventCategory {
   380→		category := parts[2]         // pull_request, issue, comment, etc.
   381→		field := parts[len(parts)-1] // title, body, etc.
   382→
   383→		// Convert to uppercase and join
   384→		categoryUpper := strings.ToUpper(strings.ReplaceAll(category, "_", ""))
   385→		fieldUpper := strings.ToUpper(field)
   386→
   387→		// Create readable name
   388→		if categoryUpper == EventCategoryPR {
   389→			categoryUpper = "PR"
   390→		}
   391→
   392→		return fmt.Sprintf("%s_%s", categoryUpper, fieldUpper)
   393→	}
   394→
   395→	// Fallback: use last part
   396→	lastPart := parts[len(parts)-1]
   397→	return strings.ToUpper(lastPart)
   398→}
   399→
   400→// extractAndParseExpressions extracts all expressions from string and parses them
   401→func (rule *CodeInjectionRule) extractAndParseExpressions(str *ast.String) []parsedExpression {
   402→	if str == nil {
   403→		return nil
   404→	}
   405→
   406→	value := str.Value
   407→	var result []parsedExpression
   408→	offset := 0
   409→
   410→	for {
   411→		idx := strings.Index(value[offset:], "${{")
   412→		if idx == -1 {
   413→			break
   414→		}
   415→
   416→		start := offset + idx
   417→		endIdx := strings.Index(value[start:], "}}")
   418→		if endIdx == -1 {
   419→			break
   420→		}
   421→
   422→		exprContent := value[start+3 : start+endIdx]
   423→		exprContent = strings.TrimSpace(exprContent)
   424→
   425→		expr, parseErr := rule.parseExpression(exprContent)
   426→		if parseErr == nil && expr != nil {
   427→			lineIdx := strings.Count(value[:start], "\n")
   428→			col := start
   429→			if lastNewline := strings.LastIndex(value[:start], "\n"); lastNewline != -1 {
   430→				col = start - lastNewline - 1
   431→			}
   432→
   433→			var pos *ast.Position
   434→			if str.Pos != nil {
   435→				pos = &ast.Position{
   436→					Line: str.Pos.Line + lineIdx,
   437→					Col:  str.Pos.Col + col,
   438→				}
   439→				if str.Literal {
   440→					pos.Line += 1
   441→				}
   442→			} else {
   443→				pos = &ast.Position{Line: lineIdx + 1, Col: col + 1}
   444→			}
   445→
   446→			result = append(result, parsedExpression{
   447→				raw:  exprContent,
   448→				node: expr,
   449→				pos:  pos,
   450→			})
   451→		}
   452→
   453→		offset = start + endIdx + 2
   454→	}
   455→
   456→	return result
   457→}
   458→
   459→// parseExpression parses a single expression string into an AST node
   460→func (rule *CodeInjectionRule) parseExpression(exprStr string) (expressions.ExprNode, *expressions.ExprError) {
   461→	if !strings.HasSuffix(exprStr, "}}") {
   462→		exprStr = exprStr + "}}"
   463→	}
   464→	l := expressions.NewTokenizer(exprStr)
   465→	p := expressions.NewMiniParser()
   466→	return p.Parse(l)
   467→}
   468→
   469→// checkUntrustedInput checks if the expression contains untrusted input
   470→func (rule *CodeInjectionRule) checkUntrustedInput(expr parsedExpression) []string {
   471→	checker := expressions.NewExprSemanticsChecker(true, nil)
   472→	_, errs := checker.Check(expr.node)
   473→
   474→	var paths []string
   475→	for _, err := range errs {
   476→		msg := err.Message
   477→		if strings.Contains(msg, "potentially untrusted") {
   478→			if idx := strings.Index(msg, "\""); idx != -1 {
   479→				endIdx := strings.Index(msg[idx+1:], "\"")
   480→				if endIdx != -1 {
   481→					path := msg[idx+1 : idx+1+endIdx]
   482→					paths = append(paths, path)
   483→				}
   484→			}
   485→		}
   486→	}
   487→
   488→	return paths
   489→}
   490→
   491→// checkUntrustedInputWithTaint checks if the expression contains untrusted input,
   492→// including tainted step outputs tracked by TaintTracker.
   493→// This extends checkUntrustedInput to detect indirect taint propagation.
   494→//
   495→// Example: If step "get-ref" writes untrusted input to $GITHUB_OUTPUT,
   496→// then steps.get-ref.outputs.ref will be detected as tainted.
   497→func (rule *CodeInjectionRule) checkUntrustedInputWithTaint(expr parsedExpression) []string {
   498→	// First check built-in untrusted inputs
   499→	paths := rule.checkUntrustedInput(expr)
   500→
   501→	// Then check tainted step outputs
   502→	if rule.taintTracker != nil {
   503→		if tainted, sources := rule.taintTracker.IsTainted(expr.node); tainted {
   504→			// Format the taint path to include the propagation chain
   505→			// e.g., "steps.get-ref.outputs.ref (tainted via github.head_ref)"
   506→			for _, source := range sources {
   507→				taintPath := fmt.Sprintf("%s (tainted via %s)", expr.raw, source)
   508→				paths = append(paths, taintPath)
   509→			}
   510→		}
   511→	}
   512→
   513→	return paths
   514→}
   515→
   516→// isDefinedInEnv checks if the expression is defined in the step's env section
   517→func (rule *CodeInjectionRule) isDefinedInEnv(expr parsedExpression, env *ast.Env) bool {
   518→	if env == nil {
   519→		return false
   520→	}
   521→
   522→	normalizedExpr := normalizeExpression(expr.raw)
   523→
   524→	if env.Vars != nil {
   525→		for _, envVar := range env.Vars {
   526→			if envVar.Value != nil && envVar.Value.ContainsExpression() {
   527→				envExprs := extractExpressionsFromString(envVar.Value.Value)
   528→				for _, envExpr := range envExprs {
   529→					if normalizeExpression(envExpr) == normalizedExpr {
   530→						return true
   531→					}
   532→				}
   533→			}
   534→		}
   535→	}
   536→
   537→	if env.Expression != nil && env.Expression.ContainsExpression() {
   538→		envExprs := extractExpressionsFromString(env.Expression.Value)
   539→		for _, envExpr := range envExprs {
   540→			if normalizeExpression(envExpr) == normalizedExpr {
   541→				return true
   542→			}
   543→		}
   544→	}
   545→
   546→	return false
   547→}
   548→
   549→// extractExpressionsFromString extracts expression contents from a string containing ${{ }}
   550→func extractExpressionsFromString(s string) []string {
   551→	var results []string
   552→	offset := 0
   553→
   554→	for {
   555→		idx := strings.Index(s[offset:], "${{")
   556→		if idx == -1 {
   557→			break
   558→		}
   559→
   560→		start := offset + idx + 3
   561→		endIdx := strings.Index(s[start:], "}}")
   562→		if endIdx == -1 {
   563→			break
   564→		}
   565→
   566→		exprContent := strings.TrimSpace(s[start : start+endIdx])
   567→		results = append(results, exprContent)
